<?php
namespace App\Models;
use App\Enums\JournalStatus;use App\Models\Concerns\BelongsToTenant;use App\Models\Concerns\HasAuditTrail;use Illuminate\Database\Eloquent\Concerns\HasUlids;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;use Illuminate\Database\Eloquent\Relations\HasMany;
class JournalEntry extends Model{use BelongsToTenant,HasAuditTrail,HasUlids;protected $fillable=['cooperative_id','accounting_period_id','reversal_of_id','reference','entry_date','source_type','source_id','event_type','description','currency','total_debit_minor','total_credit_minor','status','posted_by','posted_at','reversed_by','reversed_at','reversal_reason','metadata'];protected function casts():array{return ['entry_date'=>'date','total_debit_minor'=>'integer','total_credit_minor'=>'integer','status'=>JournalStatus::class,'posted_at'=>'datetime','reversed_at'=>'datetime','metadata'=>'array'];}public function period():BelongsTo{return $this->belongsTo(AccountingPeriod::class,'accounting_period_id');}public function lines():HasMany{return $this->hasMany(JournalEntryLine::class);}public function reversalOf():BelongsTo{return $this->belongsTo(self::class,'reversal_of_id');}}
